#!/usr/bin/env python

import subprocess
import os

def generate_requirements_txt():
    """Generate a requirements.txt file with hashes."""
    subprocess.run(['pip', 'freeze', '--all'], stdout=subprocess.PIPE)
    subprocess.run(['pip-compile', '--generate-hashes'])

def update_requirements_txt():
    """Update the requirements.txt file with the latest versions of dependencies."""
    subprocess.run(['pip-compile', '--upgrade'])
    subprocess.run(['pip-sync'])

def generate_poetry_lock():
    """Generate or update a Poetry lock file."""
    subprocess.run(['poetry', 'lock'])

def update_poetry_dependencies():
    """Update dependencies in the Poetry lock file to their latest versions."""
    subprocess.run(['poetry', 'update'])

def main():
    # Choose between using pip with requirements.txt and hashes or Poetry for dependency management
    use_pip = input("Use pip with requirements.txt (y/n)? ").strip().lower() == 'y'
    
    if use_pip:
        generate_or_update = input("Generate new or update existing requirements.txt? (generate/update): ").strip().lower()
        if generate_or_update == 'generate':
            generate_requirements_txt()
        elif generate_or_update == 'update':
            update_requirements_txt()
        else:
            print("Invalid option. Please choose 'generate' or 'update'.")
    else:
        generate_or_update = input("Generate new lock file or update existing dependencies? (lock/update): ").strip().lower()
        if generate_or_update == 'lock':
            generate_poetry_lock()
        elif generate_or_update == 'update':
            update_poetry_dependencies()
        else:
            print("Invalid option. Please choose 'lock' or 'update'.")
    
    print("Dependency management completed.")

if __name__ == "__main__":
    main()